#' Simple Dependencies Check
#'
#' @description Basic package loading for training app
#' @noRd

#' Load required packages
load_app_dependencies <- function() {

  # Required packages
  packages <- c("ggplot2", "palmerpenguins", "shiny", "golem", "ggplot2", "bslib", "reactable")

  # Check and load each package
  for(pkg in packages) {
    if(!require(pkg, character.only = TRUE, quietly = TRUE)) {
      stop("Please install package: ", pkg,
           "\nRun: install.packages('", pkg, "')")
    }
  }

  cat("✅ Packages loaded!\n")
}

#' Turn an R list into an HTML list
#'
#' @param list An R list
#' @param class a class for the list
#'
#' @return an HTML list
#' @noRd
#'
#' @examples
#' list_to_li(c("a", "b"))
#' @importFrom shiny tags tagAppendAttributes tagList
list_to_li <- function(list, class = NULL) {
  if (is.null(class)) {
    tagList(
      lapply(
        list,
        tags$li
      )
    )
  } else {
    res <- lapply(
      list,
      tags$li
    )
    res <- lapply(
      res,
      function(x) {
        tagAppendAttributes(
          x,
          class = class
        )
      }
    )
    tagList(res)
  }
}
